            <dd className="mt-1 text-sm text-gray-900">{patient.gender || '-'}</dd>
          </div>

          <div>
            <dt className="text-sm font-medium text-gray-500">Bloodgroup</dt>
            <dd className="mt-1 text-sm text-gray-900">{patient.bloodGroup || '-'}</dd>
          </div>

          <div>
            <dt className="text-sm font-medium text-gray-500">Address</dt>
            <dd className="mt-1 text-sm text-gray-900">{patient.address || '-'}</dd>
