import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const dentistSchema = z.object({
  name: z.string().min(1, "Name is required"),
  specialization: z.enum(["general", "orthodontics", "periodontics", "endodontics"]),
  licenseNumber: z.string().min(1, "Licensenumber is required"),
  experience: z.number().min(0),
});

type DentistFormData = z.infer<typeof dentistSchema>;

interface DentistFormProps {
  initialData?: Partial<DentistFormData>;
  onSubmit: (data: DentistFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function DentistForm({ initialData, onSubmit, isEdit = false }: DentistFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<DentistFormData>({
    resolver: zodResolver(dentistSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: DentistFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Name</label>
            <input {...register("name")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.name && <p className="text-red-500 text-sm mt-1">{errors.name.message}</p>}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Specialization</label>
            <select {...register("specialization")} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500">
              <option value="">Select Specialization</option>
              <option value="general">General</option>
              <option value="orthodontics">Orthodontics</option>
              <option value="periodontics">Periodontics</option>
              <option value="endodontics">Endodontics</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Licensenumber</label>
            <input {...register("licenseNumber")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.licenseNumber && <p className="text-red-500 text-sm mt-1">{errors.licenseNumber.message}</p>}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Experience</label>
            <input {...register("experience", { valueAsNumber: true })} type="number" step="any" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>
      </div>

      <div className="flex justify-end space-x-4">
        <button type="button" className="px-4 py-2 border rounded-lg hover:bg-gray-50">
          Cancel
        </button>
        <button
          type="submit"
          disabled={isSubmitting}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 flex items-center"
        >
          {isSubmitting && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
          {isEdit ? 'Update' : 'Create'} Dentist
        </button>
      </div>
    </form>
  );
}
