import React from 'react';
import { useQuery } from '@tanstack/react-query';
import { Plus, Search, Edit2, Trash2, Loader2 } from 'lucide-react';

interface Dentist {
  id: string;
  name: string;
  specialization: string;
  licenseNumber: string;
  experience: number;
}

interface DentistListProps {
  onEdit?: (item: Dentist) => void;
  onDelete?: (id: string) => void;
  onCreate?: () => void;
}

export default function DentistList({ onEdit, onDelete, onCreate }: DentistListProps) {
  const [search, setSearch] = React.useState('');
  const [page, setPage] = React.useState(1);

  const { data, isLoading, error } = useQuery({
    queryKey: ['dentists', page, search],
    queryFn: () => fetch(`/api/dentists?page=${page}&search=${search}`).then(r => r.json()),
  });

  if (isLoading) {
    return (
      <div className="flex justify-center items-center h-64">
        <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
      </div>
    );
  }

  return (
    <div className="bg-white rounded-lg shadow">
      <div className="p-4 border-b flex justify-between items-center">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
          <input
            type="text"
            placeholder="Search..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
          />
        </div>
        {onCreate && (
          <button onClick={onCreate} className="flex items-center px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700">
            <Plus className="w-5 h-5 mr-2" /> Add Dentist
          </button>
        )}
      </div>

      <div className="overflow-x-auto">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Name</th>
              <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Specialization</th>
              <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Licensenumber</th>
              <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Experience</th>
              <th className="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200">
            {data?.items?.map((item: Dentist) => (
              <tr key={item.id} className="hover:bg-gray-50">
                <td className="px-4 py-3 text-sm text-gray-900">{item.name}</td>
                <td className="px-4 py-3 text-sm text-gray-900">{item.specialization}</td>
                <td className="px-4 py-3 text-sm text-gray-900">{item.licenseNumber}</td>
                <td className="px-4 py-3 text-sm text-gray-900">{item.experience}</td>
                <td className="px-4 py-3 text-right">
                  <button onClick={() => onEdit?.(item)} className="text-blue-600 hover:text-blue-900 mr-2">
                    <Edit2 className="w-4 h-4" />
                  </button>
                  <button onClick={() => onDelete?.(item.id)} className="text-red-600 hover:text-red-900">
                    <Trash2 className="w-4 h-4" />
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="p-4 border-t flex justify-between items-center">
        <span className="text-sm text-gray-500">
          Showing {data?.items?.length || 0} of {data?.total || 0}
        </span>
        <div className="flex space-x-2">
          <button onClick={() => setPage(p => Math.max(1, p - 1))} disabled={page === 1} className="px-3 py-1 border rounded disabled:opacity-50">
            Previous
          </button>
          <button onClick={() => setPage(p => p + 1)} disabled={!data?.hasMore} className="px-3 py-1 border rounded disabled:opacity-50">
            Next
          </button>
        </div>
      </div>
    </div>
  );
}
