import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const researchProjectSchema = z.object({
  title: z.string().min(1, "Title is required"),
  abstract: z.string().optional(),
  status: z.enum(["proposed", "ongoing", "completed"]),
  funding: z.number().min(0),
  duration: z.number().min(0),
});

type ResearchProjectFormData = z.infer<typeof researchProjectSchema>;

interface ResearchProjectFormProps {
  initialData?: Partial<ResearchProjectFormData>;
  onSubmit: (data: ResearchProjectFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function ResearchProjectForm({ initialData, onSubmit, isEdit = false }: ResearchProjectFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<ResearchProjectFormData>({
    resolver: zodResolver(researchProjectSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: ResearchProjectFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Title</label>
            <input {...register("title")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.title && <p className="text-red-500 text-sm mt-1">{errors.title.message}</p>}
          </div>

          <div className="col-span-2">
            <label className="block text-sm font-medium text-gray-700 mb-1">Abstract</label>
            <textarea {...register("abstract")} rows={4} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
            <select {...register("status")} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500">
              <option value="">Select Status</option>
              <option value="proposed">Proposed</option>
              <option value="ongoing">Ongoing</option>
              <option value="completed">Completed</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Funding</label>
            <input {...register("funding", { valueAsNumber: true })} type="number" step="any" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Duration</label>
            <input {...register("duration", { valueAsNumber: true })} type="number" step="any" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
