import { Loader2 } from 'lucide-react';

const certificateSchema = z.object({
  certificateNumber: z.string().min(1, "Certificatenumber is required"),
  issuedAt: z.string(),
  grade: z.string().min(1, "Grade is required"),
  downloadUrl: z.string().min(1, "Downloadurl is required"),
});

type CertificateFormData = z.infer<typeof certificateSchema>;

interface CertificateFormProps {
  initialData?: Partial<CertificateFormData>;
  onSubmit: (data: CertificateFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function CertificateForm({ initialData, onSubmit, isEdit = false }: CertificateFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<CertificateFormData>({
    resolver: zodResolver(certificateSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: CertificateFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Certificatenumber</label>
            <input {...register("certificateNumber")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.certificateNumber && <p className="text-red-500 text-sm mt-1">{errors.certificateNumber.message}</p>}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Issuedat</label>
            <input {...register("issuedAt")} type="datetime-local" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Grade</label>
            <input {...register("grade")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.grade && <p className="text-red-500 text-sm mt-1">{errors.grade.message}</p>}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Downloadurl</label>
            <input {...register("downloadUrl")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.downloadUrl && <p className="text-red-500 text-sm mt-1">{errors.downloadUrl.message}</p>}
          </div>
      </div>

      <div className="flex justify-end space-x-4">
        <button type="button" className="px-4 py-2 border rounded-lg hover:bg-gray-50">
          Cancel
        </button>
        <button
          type="submit"
          disabled={isSubmitting}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 flex items-center"
        >
          {isSubmitting && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
          {isEdit ? 'Update' : 'Create'} Certificate
        </button>
      </div>
    </form>
  );
}
