import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const deliveryRestaurantSchema = z.object({
  name: z.string().min(1, "Name is required"),
  rating: z.number().min(0),
  deliveryTime: z.string().min(1, "Deliverytime is required"),
  minOrder: z.number().min(0),
  deliveryFee: z.number().min(0),
  isActive: z.boolean().default(false),
});

type DeliveryRestaurantFormData = z.infer<typeof deliveryRestaurantSchema>;

interface DeliveryRestaurantFormProps {
  initialData?: Partial<DeliveryRestaurantFormData>;
  onSubmit: (data: DeliveryRestaurantFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function DeliveryRestaurantForm({ initialData, onSubmit, isEdit = false }: DeliveryRestaurantFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<DeliveryRestaurantFormData>({
    resolver: zodResolver(deliveryRestaurantSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: DeliveryRestaurantFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Name</label>
            <input {...register("name")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.name && <p className="text-red-500 text-sm mt-1">{errors.name.message}</p>}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Rating</label>
            <input {...register("rating", { valueAsNumber: true })} type="number" step="any" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Deliverytime</label>
            <input {...register("deliveryTime")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.deliveryTime && <p className="text-red-500 text-sm mt-1">{errors.deliveryTime.message}</p>}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Minorder</label>
            <input {...register("minOrder", { valueAsNumber: true })} type="number" step="any" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Deliveryfee</label>
            <input {...register("deliveryFee", { valueAsNumber: true })} type="number" step="any" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div className="flex items-center">
            <input {...register("isActive")} type="checkbox" className="w-4 h-4 text-blue-600 rounded" />
            <label className="ml-2 text-sm text-gray-700">Isactive</label>
          </div>
      </div>

      <div className="flex justify-end space-x-4">
        <button type="button" className="px-4 py-2 border rounded-lg hover:bg-gray-50">
          Cancel
        </button>
        <button
          type="submit"
          disabled={isSubmitting}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 flex items-center"
        >
          {isSubmitting && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
          {isEdit ? 'Update' : 'Create'} DeliveryRestaurant
        </button>
      </div>
    </form>
  );
}
