import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const propertyViewingSchema = z.object({
  scheduledAt: z.string(),
  status: z.enum(["scheduled", "completed", "cancelled", "noshow"]),
  feedback: z.string().optional(),
  interested: z.boolean().default(false),
});

type PropertyViewingFormData = z.infer<typeof propertyViewingSchema>;

interface PropertyViewingFormProps {
  initialData?: Partial<PropertyViewingFormData>;
  onSubmit: (data: PropertyViewingFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function PropertyViewingForm({ initialData, onSubmit, isEdit = false }: PropertyViewingFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<PropertyViewingFormData>({
    resolver: zodResolver(propertyViewingSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: PropertyViewingFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          <div>
