            <select {...register("status")} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500">
              <option value="">Select Status</option>
              <option value="scheduled">Scheduled</option>
              <option value="completed">Completed</option>
              <option value="cancelled">Cancelled</option>
              <option value="noshow">Noshow</option>
            </select>
          </div>

          <div className="col-span-2">
            <label className="block text-sm font-medium text-gray-700 mb-1">Feedback</label>
            <textarea {...register("feedback")} rows={4} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div className="flex items-center">
            <input {...register("interested")} type="checkbox" className="w-4 h-4 text-blue-600 rounded" />
            <label className="ml-2 text-sm text-gray-700">Interested</label>
          </div>
      </div>

      <div className="flex justify-end space-x-4">
