import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const beneficiarySchema = z.object({
  name: z.string().min(1, "Name is required"),
  accountNumber: z.string().min(1, "Accountnumber is required"),
  bankName: z.string().min(1, "Bankname is required"),
  ifscCode: z.string().min(1, "Ifsccode is required"),
  nickname: z.string().min(1, "Nickname is required"),
});

type BeneficiaryFormData = z.infer<typeof beneficiarySchema>;

interface BeneficiaryFormProps {
  initialData?: Partial<BeneficiaryFormData>;
  onSubmit: (data: BeneficiaryFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function BeneficiaryForm({ initialData, onSubmit, isEdit = false }: BeneficiaryFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<BeneficiaryFormData>({
    resolver: zodResolver(beneficiarySchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: BeneficiaryFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
