const attendanceSchema = z.object({
  date: z.string(),
  checkIn: z.string(),
  checkOut: z.string(),
  status: z.enum(["present", "absent", "halfday", "wfh", "holiday"]),
  overtime: z.number().min(0),
});

type AttendanceFormData = z.infer<typeof attendanceSchema>;

