          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Resumeurl</label>
            <input {...register("resumeUrl")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.resumeUrl && <p className="text-red-500 text-sm mt-1">{errors.resumeUrl.message}</p>}
          </div>

          <div className="col-span-2">
