const housekeepingSchema = z.object({
  type: z.enum(["cleaning", "turndown", "maintenance"]),
  status: z.enum(["pending", "inprogress", "completed"]),
  priority: z.enum(["normal", "rush"]),
  notes: z.string().optional(),
});

