import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const seatSchema = z.object({
  row: z.string().min(1, "Row is required"),
  number: z.number().min(0),
  category: z.string().min(1, "Category is required"),
  price: z.number().min(0),
  status: z.enum(["available", "booked", "blocked"]),
});

type SeatFormData = z.infer<typeof seatSchema>;

interface SeatFormProps {
  initialData?: Partial<SeatFormData>;
  onSubmit: (data: SeatFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function SeatForm({ initialData, onSubmit, isEdit = false }: SeatFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<SeatFormData>({
    resolver: zodResolver(seatSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: SeatFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

