            {errors.row && <p className="text-red-500 text-sm mt-1">{errors.row.message}</p>}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Number</label>
            <input {...register("number", { valueAsNumber: true })} type="number" step="any" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
            <input {...register("category")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.category && <p className="text-red-500 text-sm mt-1">{errors.category.message}</p>}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Price</label>
            <input {...register("price", { valueAsNumber: true })} type="number" step="any" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
            <select {...register("status")} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500">
