import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const topicSchema = z.object({
  title: z.string().min(1, "Title is required"),
  content: z.string().optional(),
  isPinned: z.boolean().default(false),
  isLocked: z.boolean().default(false),
  views: z.number().min(0),
  replies: z.number().min(0),
  lastActivity: z.string(),
});

type TopicFormData = z.infer<typeof topicSchema>;

interface TopicFormProps {
  initialData?: Partial<TopicFormData>;
  onSubmit: (data: TopicFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function TopicForm({ initialData, onSubmit, isEdit = false }: TopicFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<TopicFormData>({
    resolver: zodResolver(topicSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: TopicFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Title</label>
            <input {...register("title")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.title && <p className="text-red-500 text-sm mt-1">{errors.title.message}</p>}
          </div>

          <div className="col-span-2">
            <label className="block text-sm font-medium text-gray-700 mb-1">Content</label>
            <textarea {...register("content")} rows={4} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div className="flex items-center">
            <input {...register("isPinned")} type="checkbox" className="w-4 h-4 text-blue-600 rounded" />
            <label className="ml-2 text-sm text-gray-700">Ispinned</label>
          </div>

          <div className="flex items-center">
            <input {...register("isLocked")} type="checkbox" className="w-4 h-4 text-blue-600 rounded" />
            <label className="ml-2 text-sm text-gray-700">Islocked</label>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Views</label>
            <input {...register("views", { valueAsNumber: true })} type="number" step="any" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Replies</label>
            <input {...register("replies", { valueAsNumber: true })} type="number" step="any" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Lastactivity</label>
            <input {...register("lastActivity")} type="datetime-local" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>
      </div>

      <div className="flex justify-end space-x-4">
        <button type="button" className="px-4 py-2 border rounded-lg hover:bg-gray-50">
          Cancel
        </button>
        <button
          type="submit"
          disabled={isSubmitting}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 flex items-center"
        >
          {isSubmitting && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
          {isEdit ? 'Update' : 'Create'} Topic
        </button>
      </div>
    </form>
  );
}
