  views: number;
  replies: number;
}

interface TopicListProps {
  onEdit?: (item: Topic) => void;
  onDelete?: (id: string) => void;
  onCreate?: () => void;
}

export default function TopicList({ onEdit, onDelete, onCreate }: TopicListProps) {
  const [search, setSearch] = React.useState('');
