  initialData?: Partial<TimeLogFormData>;
  onSubmit: (data: TimeLogFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function TimeLogForm({ initialData, onSubmit, isEdit = false }: TimeLogFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<TimeLogFormData>({
    resolver: zodResolver(timeLogSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: TimeLogFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

