import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const sLASchema = z.object({
  name: z.string().min(1, "Name is required"),
  responseTime: z.number().min(0),
  resolutionTime: z.number().min(0),
  priority: z.string().min(1, "Priority is required"),
  isActive: z.boolean().default(false),
});

type SLAFormData = z.infer<typeof sLASchema>;

interface SLAFormProps {
  initialData?: Partial<SLAFormData>;
  onSubmit: (data: SLAFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function SLAForm({ initialData, onSubmit, isEdit = false }: SLAFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<SLAFormData>({
    resolver: zodResolver(sLASchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: SLAFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
