          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Phone</label>
            <input {...register("phone")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.phone && <p className="text-red-500 text-sm mt-1">{errors.phone.message}</p>}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Designation</label>
            <input {...register("designation")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.designation && <p className="text-red-500 text-sm mt-1">{errors.designation.message}</p>}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Company</label>
            <input {...register("company")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.company && <p className="text-red-500 text-sm mt-1">{errors.company.message}</p>}
          </div>

