import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const quoteSchema = z.object({
  quoteNumber: z.string().min(1, "Quotenumber is required"),
  subtotal: z.number().min(0),
  discount: z.number().min(0),
  tax: z.number().min(0),
  total: z.number().min(0),
  status: z.enum(["draft", "sent", "accepted", "rejected"]),
});

type QuoteFormData = z.infer<typeof quoteSchema>;

interface QuoteFormProps {
  initialData?: Partial<QuoteFormData>;
  onSubmit: (data: QuoteFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function QuoteForm({ initialData, onSubmit, isEdit = false }: QuoteFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<QuoteFormData>({
    resolver: zodResolver(quoteSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: QuoteFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

