          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Tax</label>
            <input {...register("tax", { valueAsNumber: true })} type="number" step="any" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Total</label>
