interface WorkOrderFormProps {
  initialData?: Partial<WorkOrderFormData>;
  onSubmit: (data: WorkOrderFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function WorkOrderForm({ initialData, onSubmit, isEdit = false }: WorkOrderFormProps) {
