import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const serviceBookingSchema = z.object({
  scheduledAt: z.string(),
  type: z.enum(["regular", "repair", "inspection", "bodywork"]),
  status: z.enum(["scheduled", "inprogress", "completed", "cancelled"]),
  estimatedCost: z.number().min(0),
  actualCost: z.number().min(0),
});

type ServiceBookingFormData = z.infer<typeof serviceBookingSchema>;

interface ServiceBookingFormProps {
  initialData?: Partial<ServiceBookingFormData>;
  onSubmit: (data: ServiceBookingFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function ServiceBookingForm({ initialData, onSubmit, isEdit = false }: ServiceBookingFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<ServiceBookingFormData>({
    resolver: zodResolver(serviceBookingSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: ServiceBookingFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Scheduledat</label>
            <input {...register("scheduledAt")} type="datetime-local" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Type</label>
            <select {...register("type")} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500">
              <option value="">Select Type</option>
              <option value="regular">Regular</option>
              <option value="repair">Repair</option>
              <option value="inspection">Inspection</option>
              <option value="bodywork">Bodywork</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
            <select {...register("status")} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500">
              <option value="">Select Status</option>
              <option value="scheduled">Scheduled</option>
              <option value="inprogress">Inprogress</option>
              <option value="completed">Completed</option>
              <option value="cancelled">Cancelled</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Estimatedcost</label>
            <input {...register("estimatedCost", { valueAsNumber: true })} type="number" step="any" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Actualcost</label>
            <input {...register("actualCost", { valueAsNumber: true })} type="number" step="any" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
