  initialData?: Partial<ReservationFormData>;
  onSubmit: (data: ReservationFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function ReservationForm({ initialData, onSubmit, isEdit = false }: ReservationFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<ReservationFormData>({
    resolver: zodResolver(reservationSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: ReservationFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
