import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const parkingSpotSchema = z.object({
  spotNumber: z.string().min(1, "Spotnumber is required"),
  floor: z.number().min(0),
  type: z.enum(["regular", "compact", "handicap", "ev"]),
  status: z.enum(["available", "occupied", "reserved", "maintenance"]),
});

type ParkingSpotFormData = z.infer<typeof parkingSpotSchema>;

interface ParkingSpotFormProps {
  initialData?: Partial<ParkingSpotFormData>;
  onSubmit: (data: ParkingSpotFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function ParkingSpotForm({ initialData, onSubmit, isEdit = false }: ParkingSpotFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<ParkingSpotFormData>({
    resolver: zodResolver(parkingSpotSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: ParkingSpotFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Spotnumber</label>
