  total: z.number().min(0),
  notes: z.string().optional(),
});

type SalonAppointmentFormData = z.infer<typeof salonAppointmentSchema>;

interface SalonAppointmentFormProps {
  initialData?: Partial<SalonAppointmentFormData>;
  onSubmit: (data: SalonAppointmentFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function SalonAppointmentForm({ initialData, onSubmit, isEdit = false }: SalonAppointmentFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<SalonAppointmentFormData>({
    resolver: zodResolver(salonAppointmentSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: SalonAppointmentFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          <div>
